#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX 1000

int minTime(char grid[][MAX], int n, int m) {
    int i, j, time = 0;
    int visited[n][m];
    int queue[n * m][2];
    int front = 0, rear = 0;

    // Find the first '*' in the grid
    for (i = 0; i < n; i++) {
        for (j = 0; j < m; j++) {
            if (grid[i][j] == '*') {
                queue[rear][0] = i;
                queue[rear][1] = j;
                rear++;
                visited[i][j] = 1;
                break;
            }
        }
        if (rear > 0) break;
    }

    // Perform BFS
    while (front < rear) {
        int x = queue[front][0];
        int y = queue[front][1];
        front++;

        // Explore all adjacent houses
        for (i = -1; i <= 1; i++) {
            for (j = -1; j <= 1; j++) {
                int nx = x + i;
                int ny = y + j;

                if (nx >= 0 && nx < n && ny >= 0 && ny < m && visited[nx][ny] == 0) {
                    queue[rear][0] = nx;
                    queue[rear][1] = ny;
                    rear++;
                    visited[nx][ny] = 1;
                    if (grid[nx][ny] == '*') time++;
                }
            }
        }
    }

    return time;
}

int main() {
    int T, n, m, i, j;
    char grid[1000][1000];

    scanf("%d", &T);

    while (T--) {
        scanf("%d %d", &n, &m);

        for (i = 0; i < n; i++) {
            scanf("%s", grid[i]);
        }

        printf("%d\n", minTime(grid, n, m));
    }

    return 0;
}

