int minTime(vector<vector<char>>& grid, int n, int m) {
    int time = 0;
    vector<vector<int>> visited(n, vector<int>(m, 0));
    queue<pair<int, int>> q;

    // Find the first '*' in the grid
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < m; j++) {
            if (grid[i][j] == '*') {
                q.push({i, j});
                visited[i][j] = 1;
                break;
            }
        }
        if (!q.empty()) break;
    }

    // Perform BFS
    while (!q.empty()) {
        int x = q.front().first;
        int y = q.front().second;
        q.pop();

        // Explore all adjacent houses
        for (int i = -1; i <= 1; i++) {
            for (int j = -1; j <= 1; j++) {
                int nx = x + i;
                int ny = y + j;

                if (nx >= 0 && nx < n && ny >= 0 && ny < m && visited[nx][ny] == 0) {
                    q.push({nx, ny});
                    visited[nx][ny] = 1;
                    if (grid[nx][ny] == '*') time++;
                }
            }
        }
    }

    return time;
}

