import java.util.Queue;
import java.util.LinkedList;
import java.util.Scanner;

public class Main {
    static final int MAX = 1000;

    public static int minTime(char[][] grid, int n, int m) {
        int time = 0;
        boolean[][] visited = new boolean[n][m];
        Queue<int[]> q = new LinkedList<>();

        // Find the first '*' in the grid
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < m; j++) {
                if (grid[i][j] == '*') {
                    q.add(new int[] {i, j});
                    visited[i][j] = true;
                    break;
                }
            }
            if (!q.isEmpty()) break;
        }

        // Perform BFS
        while (!q.isEmpty()) {
            int[] curr = q.poll();
            int x = curr[0];
            int y = curr[1];

            // Explore all adjacent houses
            for (int i = -1; i <= 1; i++) {
                for (int j = -1; j <= 1; j++) {
                    int nx = x + i;
                    int ny = y + j;

                    if (nx >= 0 && nx < n && ny >= 0 && ny < m && !visited[nx][ny]) {
                        q.add(new int[] {nx, ny});
                        visited[nx][ny] = true;
                        if (grid[nx][ny] == '*') time++;
                    }
                }
            }
        }

        return time;
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();

        while (T-- > 0) {
            int n = sc.nextInt();
            int m = sc.nextInt();
            char[][] grid = new char[n][m];

            for (int i = 0; i < n; i++) {
                String s = sc.next();
                for (int j = 0; j < m; j++) {
                    grid[i][j] = s.charAt(j);
                }
            }

            System.out.println(minTime(grid, n, m));
        }
    }
}

