from collections import deque

MAX = 1000

def minTime(grid, n, m):
    time = 0
    visited = [[False for _ in range(m)] for _ in range(n)]
    q = deque()

    # Find the first '*' in the grid
    for i in range(n):
        for j in range(m):
            if grid[i][j] == '*':
                q.append((i, j))
                visited[i][j] = True
                break
        if q:
            break

    # Perform BFS
    while q:
        x, y = q.popleft()

        # Explore all adjacent houses
        for i in range(-1, 2):
            for j in range(-1, 2):
                nx, ny = x + i, y + j

                if 0 <= nx < n and 0 <= ny < m and not visited[nx][ny]:
                    q.append((nx, ny))
                    visited[nx][ny] = True
                    if grid[nx][ny] == '*':
                        time += 1

    return time

